using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// --- 1. GetTypeInfo<T>(): strongly-typed metadata retrieval ---
var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> → Type = {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Ada", 36), personInfo);
Console.WriteLine($"Serialized: {json}");

// --- 2. TryGetTypeInfo<T>(): check-without-throwing ---

// 2a. Type the resolver CAN handle → returns true
if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? found))
    Console.WriteLine($"TryGet Person   → found ({found!.Type.Name})");
else
    Console.WriteLine("TryGet Person   → not available");

// 2b. Use a custom resolver that only knows about Person,
//     so probing for int[] will return false — no exception.
var limited = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
        .WithAddedModifier(ti =>
        {
            // reject everything except Person
            if (ti.Type != typeof(Person))
                throw new NotSupportedException();
        })
};

if (limited.TryGetTypeInfo<int[]>(out JsonTypeInfo<int[]>? arrInfo))
    Console.WriteLine($"TryGet int[]    → found ({arrInfo!.Type.Name})");
else
    Console.WriteLine("TryGet int[]    → not available (no exception thrown!)");

// --- done ---
public record Person(string Name, int Age);

